// // This module implements a D flip-flop with positive edge-triggered clock and active-low reset
module dff_negedge_reset (
    input D,
    input C,
    input R,
    output reg Q
);

always @ (negedge C) begin
    if (R) begin
        Q <= 1'b0;
    end else begin
        Q <= D;
    end
end

endmodule
